import axios from 'axios';
import router from './router';


//axios配置
axios.defaults.timeout = 6000;
//axios.defaults.baseURL = 'https://api.github.com';
// axios.defaults.headers.common['token'] = localStorage.getItem('token');   //也可以在这里发送token字段
// console.log(' window.localStorage["token"]=>', window.localStorage["token"]);
// console.log('localStorage.getItem(\'token\'=>',localStorage.getItem('token'));

//request 拦截器
axios.interceptors.request.use(
  config => {
    console.log('request拦截器信息，config=>',config);
    if (localStorage.token) {
      console.log('前端储存在localstorge中的token=>',localStorage.token);
      config.headers.authorization = localStorage.token;
    }
    return config;
  },
  //请求错误时做什么
  err => {
    return Promise.reject(err);
  }
);
//respone拦截器
axios.interceptors.response.use(
  response => {
    if(response.status === 200) {
      return response;
    }
  },
  error => {
    if(response.data.code == 404){
      console.log('token错误或已经失效！');
      router.replace({ //重新跳转到登录页面
        path: 'login',
      });
    }
    return Promise.reject(error.response);
  }
);

export default axios;




