// The Vue build version to load with the `import` command
// (runtime-only or standalone) has been set in webpack.base.conf with an alias.
import Vue from 'vue'
import App from './App'
import axios from './http';   //npm install --save axios vue-axios
import md5 from 'js-md5';     //npm install --save js-md5
import router from './router' //使用路由管理者
import iView from 'iview';    // 导入组件库
import 'iview/dist/styles/iview.css'; // 导入样式
import echarts from 'echarts';
import ElementUI from 'element-ui';
import 'element-ui/lib/theme-chalk/index.css';
Vue.use(ElementUI);
Vue.prototype.$echarts = echarts;
// import VueResource from 'vue-resource';
// Vue.use(VueResource);
Vue.use(iView);
Vue.prototype.$md5 = md5;      //使用md5加密技术
Vue.prototype.$http = axios;   //解决跨域调接口
window.eventBus = new Vue();   //注册全局事件对象
Vue.config.productionTip = false;

/* eslint-disable no-new */
new Vue({
  el: '#app',
  router,
  components: { App },
  template: '<App/>' ,
  // render: h => h(App)  //利用render函数使用路由
})



