import Vue from 'vue'
import Router from 'vue-router'
Vue.use(Router);

const routes = [
    {
      path     : '/',
      name     : 'login',
      component: r => require.ensure([], () => r(require('@/components/login/login')))
    },
    {
      path     :'/mainpage',
      name     :'mainpage',
      component: r => require.ensure([], () => r(require('@/components/home/mainpage'))),
      children:[
        {
          path:'/echars1',
          name:'echars1',
          component: r => require.ensure([], () => r(require('@/components/home/echars1')))
        },
        {
          path:'/user',
          name:'user',
          component: r => require.ensure([], () => r(require('@/components/user/user')))
        },
        {
          path:'/book',
          name:'book',
          component:r => require.ensure([], () => r(require('@/components/book/book')))
        },

        {
          path:'/contentme',
          name:'contentme',
          component:r => require.ensure([], () => r(require('@/components/home/contentme')))
        }

      ]
    },

  ];
const router = new Router({
  routes
});
// 拦截导航实例
//   path: '/',
//   name: 'login',
//   component: Login,
//   meta: { requireAuth: false } // 添加该字段，表示进入这个路由是需要登录的

//注册全局钩子用来拦截导航
router.beforeEach((to, from, next) => {
  //获取localStorage里面的token
  let token = localStorage.token;
  //判断要去的路由有没有requiresAuth,是否需要获取权限
  if(to.meta.requiresAuth){
    if(token){
      console.log('token存在')
      next();
    }else{
      console.log('token不存在或过期')
      next({
        path: '/login',
        query: { redirect: to.fullPath } // 将刚刚要去的路由path（却无权限）作为参数，登录成功后直接跳转到该路由
      });
    }
  }else{
    next();//如果无需token,那么直接调用
  }
});
export default router;



